import { useNavigate } from "react-router-dom";
import { useState } from "react";

const sampleRecipes = [
  {
    url: "https://www.justonecookbook.com/classic-mentaiko-pasta",
    name: "Mentaiko Pasta",
    image: "https://www.justonecookbook.com/wp-content/uploads/2022/01/Mentaiko-Pasta-0123-I.jpg",
    servings: 2,
    total_time: 20,
    ingredients: [
      { amount: "2", unit: "Tbsp", item: "Diamond Crystal kosher salt" },
      { amount: "8", unit: "oz", item: "spaghetti" },
      { amount: "2", unit: "sacs", item: "spicy salted pollock roe" },
      { amount: "2", unit: "Tbsp", item: "whole milk" },
      { amount: "2", unit: "Tbsp", item: "heavy whipping cream" },
      { amount: "2", unit: "Tbsp", item: "unsalted butter" },
      { amount: "1", unit: "Tbsp", item: "soy sauce" },
      { amount: null, unit: null, item: "freshly ground black pepper" },
    ],
    instructions: [
      "1. Gather all the ingredients.",
      "2. Bring a large pot of water to a boil and add salt.",
      "3. Cook spaghetti until al dente, about 10 minutes.",
      "4. In a large bowl combine milk, cream, butter and soy sauce.",
      "5. Add the roe and stir well.",
      "6. Drain pasta and toss with sauce until coated.",
    ],
  },
  {
    url: "https://www.allrecipes.com/recipe/23600/worlds-best-lasagna",
    name: "Classic Lasagna",
    image: "https://www.allrecipes.com/thmb/lasagna.jpg",
    servings: 8,
    total_time: 150,
    ingredients: [
      { amount: "1", unit: "lb", item: "sweet Italian sausage" },
      { amount: "3/4", unit: "lb", item: "lean ground beef" },
      { amount: "1", unit: "can", item: "crushed tomatoes" },
      { amount: "2", unit: "cans", item: "tomato paste" },
      { amount: "12", unit: "pieces", item: "lasagna noodles" },
      { amount: "16", unit: "oz", item: "ricotta cheese" },
      { amount: "1", unit: null, item: "egg" },
      { amount: null, unit: null, item: "salt and pepper to taste" },
    ],
    instructions: [
      "1. Cook sausage and ground beef in a pot over medium heat.",
      "2. Add crushed tomatoes and tomato paste, simmer for 30 minutes.",
      "3. Cook lasagna noodles according to package directions.",
      "4. Mix ricotta cheese with egg, salt and pepper.",
      "5. Layer noodles, meat sauce and ricotta in a baking dish.",
      "6. Bake at 375°F for 50 minutes until bubbly.",
    ],
  },
];

export default function Collection() {
  const [selectedRecipe, setSelectedRecipe] = useState(null);

  return (
    <div style={styles.page}>
      <h2 style={styles.title}>My Saved Recipes</h2>
      <p style={styles.count}>{sampleRecipes.length} recipes</p>

      {/* Recipe Grid */}
      <div style={styles.grid}>
        {sampleRecipes.map((recipe, i) => (
          <div
            key={i}
            style={styles.card}
            onClick={() => setSelectedRecipe(recipe)}
            onMouseEnter={e => e.currentTarget.style.borderColor = "#9ca3af"}
            onMouseLeave={e => e.currentTarget.style.borderColor = "#e5e7eb"}
          >
            {/* {recipe.image && (
              <img src={recipe.image} alt={recipe.name} style={styles.cardImage} />
            )} */}
            <div style={styles.cardBody}>
              <p style={styles.cardName}>{recipe.name}</p>
              <p style={styles.cardMeta}>
                {recipe.total_time && `${recipe.total_time} mins · `}
                {recipe.ingredients.length} ingredients
              </p>
            </div>
          </div>
        ))}
      </div>

      {/* Popup Overlay */}
      {selectedRecipe && (
        <div style={styles.overlay} onClick={() => setSelectedRecipe(null)}>
          <div style={styles.popup} onClick={e => e.stopPropagation()}>

            {/* Popup Header */}
            <div style={styles.popupHeader}>
              <div>
                <h2 style={styles.popupTitle}>{selectedRecipe.name}</h2>
                <p style={styles.popupMeta}>
                  {selectedRecipe.total_time && `${selectedRecipe.total_time} mins · `}
                  {selectedRecipe.servings && `Serves ${selectedRecipe.servings} · `}
                  {selectedRecipe.ingredients.length} ingredients
                </p>
              </div>
              <button style={styles.closeBtn} onClick={() => setSelectedRecipe(null)}>✕</button>
            </div>

            <div style={styles.popupBody}>

              {/* Ingredients */}
              <div style={styles.section}>
                <p style={styles.sectionTitle}>Ingredients</p>
                {selectedRecipe.ingredients.map((ing, i) => (
                  <div key={i} style={styles.ingredientRow}>
                    <span style={styles.ingredientAmount}>
                      {[ing.amount, ing.unit].filter(Boolean).join(" ") || "—"}
                    </span>
                    <span style={styles.ingredientItem}>{ing.item}</span>
                  </div>
                ))}
              </div>

              {/* Instructions */}
              <div style={styles.section}>
                <p style={styles.sectionTitle}>Instructions</p>
                {selectedRecipe.instructions.map((step, i) => (
                  <p key={i} style={styles.step}>{step}</p>
                ))}
              </div>

            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const styles = {
  page: {
    maxWidth: "900px",
    margin: "48px auto",
    padding: "0 24px",
  },
  title: { fontSize: "22px", fontWeight: "500", marginBottom: "4px" },
  count: { fontSize: "13px", color: "#9ca3af", marginBottom: "28px" },
  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))",
    gap: "16px",
  },
  card: {
    border: "1px solid #e5e7eb",
    borderRadius: "10px",
    overflow: "hidden",
    cursor: "pointer",
    background: "#fff",
    transition: "border-color 0.15s",
  },
  cardImage: { width: "100%", height: "130px", objectFit: "cover" },
  cardBody: { padding: "12px" },
  cardName: { fontSize: "14px", fontWeight: "500", marginBottom: "4px" },
  cardMeta: { fontSize: "12px", color: "#9ca3af" },

  // Overlay
  overlay: {
    position: "fixed",
    inset: 0,
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    zIndex: 1000,
  },
  popup: {
    background: "#fff",
    borderRadius: "12px",
    width: "100%",
    maxWidth: "680px",
    maxHeight: "80vh",
    overflow: "hidden",
    display: "flex",
    flexDirection: "column",
    margin: "0 16px",
  },
  popupHeader: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "flex-start",
    padding: "24px 24px 16px",
    borderBottom: "1px solid #e5e7eb",
  },
  popupTitle: { fontSize: "20px", fontWeight: "500", marginBottom: "4px" },
  popupMeta: { fontSize: "13px", color: "#9ca3af" },
  closeBtn: {
    background: "none",
    border: "none",
    fontSize: "18px",
    cursor: "pointer",
    color: "#9ca3af",
    padding: "4px 8px",
  },
  popupBody: {
    overflowY: "auto",
    padding: "24px",
    display: "flex",
    flexDirection: "column",
    gap: "28px",
  },
  section: {},
  sectionTitle: {
    fontSize: "11px",
    fontWeight: "600",
    letterSpacing: "0.08em",
    textTransform: "uppercase",
    color: "#9ca3af",
    marginBottom: "12px",
  },
  ingredientRow: {
    display: "flex",
    gap: "12px",
    padding: "8px 0",
    borderBottom: "1px solid #f3f4f6",
    fontSize: "14px",
  },
  ingredientAmount: { minWidth: "80px", color: "#6b7280" },
  ingredientItem: { color: "#111827" },
  step: {
    fontSize: "14px",
    lineHeight: "1.7",
    color: "#374151",
    marginBottom: "12px",
  },
};
